package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal;

import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalPriveRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.AbstractBijdrageMetPercentageBase;
import be.schaubroeck.lpb.rkm.rekenresultaat.service.util.RekenresultaatBedrag;
import be.schaubroeck.lpb.tools.RszConstant;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.RszConstantType;
import be.schaubroeck.lpb.tools.rsz.dmfa.KengetalDmfa;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import org.joda.time.LocalDate;

import java.math.BigDecimal;

//810
public class BijdrageFso extends AbstractBijdrageMetPercentageBase {

    public static final MoneyKey MONEY_KEY_INHOUDING = RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_FONDS_SLUITING_ONDERNEMING_KEY;

    public static final RekenresultaatBedrag REKENRESULTAAT_BEDRAG_BASIS = RekenresultaatBedrag.BASIS_FONDS_SLUITING_ONDERNEMING;
    public static final RekenresultaatBedrag REKENRESULTAAT_BEDRAG_INHOUDING = RekenresultaatBedrag.PATRONALE_BIJZONDERE_BIJDRAGE_FSO;

    private final DmfapplWnkengetal dmfapplWnkengetal;


    public BijdrageFso(RszConstantService rszConstantService, DmfapplWnkengetal dmfapplWnkengetal) {
        super(rszConstantService);
        this.dmfapplWnkengetal = dmfapplWnkengetal;
    }

    public BigDecimal getPercentage(SleutelGegevens gegevens, LocalDate zoekDatum) {
        RszConstantType type = bepaalType(gegevens, zoekDatum);
        return getWerkgeversPercentage(zoekDatum, gegevens.getWerkgeversCategorie(), dmfapplWnkengetal, type.getCode());
    }

    public RszConstantType bepaalType(SleutelGegevens gegevens, LocalDate zoekDatum) {
        WerkgeversCategorie werkgeversCategorie = gegevens.getWerkgeversCategorie();
        DmfapplWnkengetal werknemersKengetal = gegevens.getWerknemersKengetal();
        RszConstant rszConstant = getRszConstant(zoekDatum, werkgeversCategorie, werknemersKengetal, 0);
        if (rszConstant == null) {
            rszConstant = getRszConstant(zoekDatum, werkgeversCategorie, werknemersKengetal, 1);
        }

        KengetalDmfa kengetal = new KengetalDmfa(gegevens.getWerknemersKengetal());
        if ((rszConstant != null && rszConstant.getLoonMatigingsPercentage().signum() == 0) || kengetal.isGesco()) {
            return RszConstantType.TYPE_2;
        } else {
            return RszConstantType.TYPE_0;
        }
    }
}
